import json

# Create invoice for Acme Corp
invoice_result = tools.create_invoice(
    client_name="Acme Corp",
    items=[
        {"description": "Consulting Services", "quantity": 50, "price": 200},
        {"description": "Project Management", "quantity": 20, "price": 150}
    ],
    due_days=30
)

# Parse the invoice result
try:
    invoice_data = json.loads(invoice_result)
except:
    invoice_data = {"invoice_id": None}

# Get invoice_id
invoice_id = invoice_data.get("invoice_id") or invoice_data.get("id")

# Mark invoice as sent if we have an invoice_id
if invoice_id:
    tools.update_invoice_status(invoice_id, "sent")
    tools.record_partial_payment(invoice_id, 8000)
    tools.record_partial_payment(invoice_id, 500000)

# Get all invoices for Acme Corp
invoices_result = tools.get_invoices(client_name="Acme Corp")
invoices_data = json.loads(invoices_result)

# Get checking account balance
balance_result = tools.get_account_balance("checking")
balance_data = json.loads(balance_result)

# Get financial summary
summary_result = tools.get_financial_summary()
summary_data = json.loads(summary_result)

# Build summary from the invoice data
invoice = invoices_data[0] if invoices_data else {}
total_amount = invoice.get("total_amount", 0) or 0
paid_amount = invoice.get("paid_amount", 0) or 0
remaining = float(total_amount) - float(paid_amount)

result = f"""=== Invoice Summary ===
Invoice ID: {invoice_id}
Client: Acme Corp
Total Amount: ${float(total_amount):,.2f}
Paid Amount: ${float(paid_amount):,.2f}
Remaining Amount: ${remaining:,.2f}
Status: {invoice.get('status', 'N/A')}

=== Checking Account Balance ===
Balance: ${float(balance_data.get('balance', 0)):,.2f}

=== Total Income from Invoice Payments ===
Total Invoice Payment Income: ${float(summary_data.get('income', 0)):,.2f}
"""

